Run multiple nodes in parallel and merge their results. from synapsekit.graph import StateGraph from synapsekit.llms.openai import OpenAILLM import asyncio llm = OpenAILLM(model="gpt-4o-mini") async def split_node(state: dict) -> dict: return {**state, "ready": True} async def search_news(state: dict) -> dict: result = await llm.complete(f"What are the latest news about {state['topic']}?") return {**state, "news": result} async def search_wiki(state: dict) -> dict: result = await llm.complete(f"Give a Wikipedia-style summary of {state['topic']}") return {**state, "wiki": result} async def search_papers(state: dict) -> dict: result = await llm.complete(f"What recent research papers exist on {state['topic']}?") return {**state, "papers": result} async def merge_node(state: dict) -> dict: summary = await llm.complete( f"Combine these sources:
News: {state['news']}
" f"Wiki: {state['wiki']}
Papers: {state['papers']}" ) return {**state, "final": summary} workflow = StateGraph() workflow.add_node("split", split_node) workflow.add_node("news", search_news) workflow.add_node("wiki", search_wiki) workflow.add_node("papers", search_papers) workflow.add_node("merge", merge_node) workflow.set_entry_point("split") workflow.add_parallel_edges("split", ["news", "wiki", "papers"]) workflow.add_join_edge(["news", "wiki", "papers"], "merge") workflow.set_finish_point("merge") graph = workflow.compile() result = await graph.run({"topic": "Mixture of Experts LLMs"}) print(result["final"])

Serve a streaming graph over Server-Sent Events from a FastAPI endpoint. from fastapi import FastAPI from fastapi.responses import StreamingResponse from synapsekit.graph import StateGraph import json app = FastAPI() graph = workflow.compile() # your compiled graph @app.post("/run") async def run_graph(body: dict): async def event_stream(): async for event in graph.stream(body): data = json.dumps({"type": event.type, "content": event.content}) yield f"data: {data}

