" return StreamingResponse(event_stream(), media_type="text/event-stream") Client-side consumption: const es = new EventSource('/run'); es.onmessage = (e) => { const data = JSON.parse(e.data); if (data === '[DONE]') { es.close(); return; } process.stdout.write(data.content); };

