StateGraph supports human-in-the-loop interrupts. Handle GraphInterruptError to pause, collect input, and resume. import asyncio from synapsekit.graph import StateGraph from synapsekit.graph.exceptions import GraphInterruptError async def draft_content(state: dict) -> dict: return {"draft": f"Draft response for: {state['input']}"} async def review_gate(state: dict) -> dict: """Interrupt here for human review.""" from synapsekit.graph import interrupt approved = await interrupt( state, message=f"Please review this draft:

{state['draft']}

Approve? (yes/no)", ) return {"approved": approved, "review_done": True} async def publish(state: dict) -> dict: if state.get("approved"): return {"status": "published", "content": state["draft"]} return {"status": "rejected"} async def main(): graph = StateGraph() graph.add_node("draft", draft_content) graph.add_node("review", review_gate) graph.add_node("publish", publish) graph.add_edge("draft", "review") graph.add_edge("review", "publish") graph.set_entry_point("draft") compiled = graph.compile(checkpointer="sqlite") # Persist state for resume thread_id = "content-review-001" # First run — will pause at the interrupt node try: result = await compiled.ainvoke( {"input": "Write a blog post about RAG"}, config={"thread_id": thread_id}, ) except GraphInterruptError as e: print(f"Paused: {e.message}") # Expected output: Paused: Please review this draft: ... # Simulate human review human_input = "yes" print(f"Human input: {human_input}") # Resume from the interrupt point result = await compiled.ainvoke( {"input": human_input}, config={"thread_id": thread_id}, ) print(f"Final status: {result['status']}") # Expected output: Final status: published asyncio.run(main())

